CREATE FUNCTION public.get_monthly_brokerages() RETURNS TABLE(bank_id integer, monthly_brokerage_sum double precision, monthly_trade_count numeric, swaption_monthly_brokerage_sum double precision, swaption_monthly_trade_count numeric)
    LANGUAGE sql
    AS $$
SELECT COALESCE(sw.bank_id, op.bank_id) AS bank_id, COALESCE(sw.monthly_brokerage_sum, 0) AS monthly_brokerage_sum, 
COALESCE(sw.monthly_trade_count, 0) AS monthly_trade_count, COALESCE(op.swaption_monthly_brokerage_sum, 0) AS swaption_monthly_brokerage_sum,
COALESCE(op.swaption_monthly_trade_count, 0) AS swaption_monthly_trade_count FROM (

	SELECT d.bank_id, SUM(z.monthly_brokerage_sum) AS monthly_brokerage_sum, SUM(z.monthly_trade_count) AS monthly_trade_count
	FROM public.bank_divisions d
	RIGHT JOIN 
		(
		SELECT COALESCE(o.offer_bank_division_id, b.bid_bank_division_id) as bank_division_id,
			(COALESCE(o.offer_bro_sum, 0) + COALESCE(b.bid_bro_sum, 0)) as monthly_brokerage_sum,
			(COALESCE(o.offer_bro_count, 0) + COALESCE(b.bid_bro_count, 0)) as monthly_trade_count
		FROM
			(SELECT SUM(offer_brokerage) as offer_bro_sum, COUNT(offer_brokerage) as offer_bro_count, offer_bank_division_id FROM public.trades 
			WHERE EXTRACT(MONTH FROM timestamp AT TIME ZONE '-10') = EXTRACT(MONTH FROM NOW() AT TIME ZONE '-10')
			AND EXTRACT(YEAR FROM timestamp AT TIME ZONE '-10') = EXTRACT(YEAR FROM NOW() AT TIME ZONE '-10')
			GROUP BY offer_bank_division_id) o
		FULL JOIN
			(SELECT SUM(bid_brokerage) as bid_bro_sum, COUNT(bid_brokerage) as bid_bro_count, bid_bank_division_id FROM public.trades
			WHERE EXTRACT(MONTH FROM timestamp AT TIME ZONE '-10') = EXTRACT(MONTH FROM NOW() AT TIME ZONE '-10')
			AND EXTRACT(YEAR FROM timestamp AT TIME ZONE '-10') = EXTRACT(YEAR FROM NOW() AT TIME ZONE '-10')
			GROUP BY bid_bank_division_id) b
		ON (o.offer_bank_division_id = b.bid_bank_division_id)
		) z
	ON d.bank_division_id = z.bank_division_id GROUP BY bank_id
	
	
) sw FULL JOIN (

	SELECT d.bank_id, SUM(z.swaption_monthly_brokerage_sum) AS swaption_monthly_brokerage_sum, SUM(z.swaption_monthly_trade_count) AS swaption_monthly_trade_count
	FROM public.bank_divisions d
	FULL JOIN 
		(
		SELECT COALESCE(o.seller_bank_division, b.buyer_bank_division) as bank_division,
			(COALESCE(o.seller_bro_sum, 0) + COALESCE(b.buyer_bro_sum, 0)) as swaption_monthly_brokerage_sum,
			(COALESCE(o.seller_bro_count, 0) + COALESCE(b.buyer_bro_count, 0)) as swaption_monthly_trade_count
		FROM
			(SELECT SUM(buyer_brokerage) as buyer_bro_sum, COUNT(buyer_brokerage) as buyer_bro_count, buyer_bank_division FROM public.swaption_orders
			WHERE EXTRACT(MONTH FROM timestamp AT TIME ZONE '-10') = EXTRACT(MONTH FROM NOW() AT TIME ZONE '-10')
			AND EXTRACT(YEAR FROM timestamp AT TIME ZONE '-10') = EXTRACT(YEAR FROM NOW() AT TIME ZONE '-10')
			GROUP BY buyer_bank_division) b
		FULL JOIN
			(SELECT SUM(seller_brokerage) as seller_bro_sum, COUNT(seller_brokerage) as seller_bro_count, seller_bank_division FROM public.swaption_orders 
			WHERE EXTRACT(MONTH FROM timestamp AT TIME ZONE '-10') = EXTRACT(MONTH FROM NOW() AT TIME ZONE '-10')
			AND EXTRACT(YEAR FROM timestamp AT TIME ZONE '-10') = EXTRACT(YEAR FROM NOW() AT TIME ZONE '-10')
			GROUP BY seller_bank_division) o
		ON (o.seller_bank_division = b.buyer_bank_division)
		) z
	ON d.bank_division_id = z.bank_division GROUP BY d.bank_id
	
) op ON sw.bank_id = op.bank_id
-- WHERE sw.monthly_trade_count IS NOT NULL OR op.swaption_monthly_trade_count IS NOT NULL
ORDER BY bank_id;
$$;


