-- TOC entry 311 (class 1255 OID 20872)
-- Name: swap_custom_whiteboard_ids(integer, integer, integer); Type: PROCEDURE; Schema: public; Owner: potrade
--

CREATE PROCEDURE public.swap_custom_whiteboard_ids(b_id integer, id1 integer, id2 integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
	IF (SELECT COUNT(*) FROM custom_whiteboards WHERE broker_id = b_id AND board_id IN (id1, id2)) = 2 THEN
		UPDATE custom_whiteboards
		SET board_id = -board_id 
		WHERE broker_id = b_id AND board_id in (id1, id2);

		UPDATE custom_whiteboards 
		SET board_id = CASE board_id WHEN -id1 THEN id2
					 				WHEN -id2 THEN id1
					 	END
		WHERE broker_id = b_id AND board_id in (-id1, -id2);
	ELSE
		RAISE EXCEPTION 'Failed to find two custom whiteboards using the given parameters.';
	END IF;
END;
$$;


ALTER PROCEDURE public.swap_custom_whiteboard_ids(b_id integer, id1 integer, id2 integer) OWNER TO potrade;

--
-- TOC entry 313 (class 1255 OID 21578)
-- Name: update_confo_mw_values(integer, jsonb); Type: PROCEDURE; Schema: public; Owner: potrade
--

CREATE PROCEDURE public.update_confo_mw_values(id_to_update integer, INOUT update_result jsonb DEFAULT NULL::jsonb)
    LANGUAGE plpgsql
    AS $$
DECLARE
    row_data jsonb;
    key_text TEXT;
	mw_ids TEXT[];
	t_id INT;
	
	input_string TEXT;
    output_string TEXT;
    values_array TEXT[];
    prefix_length INT;
    i INT;
    j INT;
	regex TEXT;
BEGIN
    -- Fetch the JSON data for the specified confo_id
    SELECT confos INTO row_data
    FROM confos
    WHERE confo_id = id_to_update;
	
	-- Fetch the markit_id's for the specified trade_ids
    FOR t_id IN
        SELECT unnest(trade_ids) FROM confos
		WHERE confo_id = id_to_update
    LOOP
        mw_ids = array_append(mw_ids, (SELECT (CASE WHEN markit_id is NULL THEN 'NA' ELSE markit_id::TEXT END) FROM trades WHERE trade_id = t_id)::TEXT);
    END LOOP;

    -- Iterate through each key in the JSON object
    FOR key_text IN
        SELECT jsonb_object_keys(row_data)
    LOOP
		-- Get Confo for bank
		input_string := row_data->>key_text;
		
		-- Find the position of 'MW: '
		prefix_length := position('MW: ' IN input_string) + 4;
		
		-- Extract the substring after 'MW: '
		output_string := substr(input_string, prefix_length);

		-- Check if there are commas in the substring
		IF position(',' IN output_string) > 0 THEN
			-- Split the substring by comma and space into an array if there are commas
			values_array := string_to_array(output_string, ', ');
		ELSE
			-- If there are no commas, just use the whole substring as a single element in the array
			values_array := ARRAY[output_string];
		END IF;

		-- Iterate over the array elements
		regex := '';
		FOR i IN 1..array_length(values_array, 1) LOOP
			-- Replace 'NA' with the respective value from the replacement array
			IF values_array[i] = 'NA' THEN
				output_string := regexp_replace(output_string, ('\y' || regex || values_array[i] || '\y'), (regex || mw_ids[i]));
				regex  = regex || mw_ids[i];
			ELSE
				regex  = regex || values_array[i];
			END IF;
			
			IF i <> array_length(values_array, 1) THEN
				regex  = regex || ', ';
			END IF;
		END LOOP;

		-- Concatenate the prefix with the modified substring
		output_string := left(input_string, prefix_length - 1) || output_string;
		
        -- Update the value of each banks confo
        row_data = jsonb_set(row_data, ARRAY[key_text], to_jsonb(output_string));
    END LOOP;

    -- Update the row with the modified JSON
    UPDATE confos
    SET confos = row_data
    WHERE confo_id = id_to_update
	RETURNING to_jsonb('{"confo_id": ' || confo_id || ', "confos": ' || confos || '}') INTO update_result;
END; $$;


ALTER PROCEDURE public.update_confo_mw_values(id_to_update integer, INOUT update_result jsonb) OWNER TO potrade;

